$(document).ready(function() {
    var side = $(".header_container .cat .side_box");
    var over = $('.side_overlay');
    var main = $('#main_page');
    var about = $('#about_page');
    var location = $('#location_page');
    var facilities = $('#facilities_page');
    var board = $('#board_page');
    var rooms = $('#rooms_page');
    var detail = $('#detail_page');
    var contact = $('#contact_page');
    var windowScrollTop = $(window).scrollTop();
    var app = {
        common: function() {
            $(window).resize(function(e) {
                windowWidth = window.innerWidth;
                windowHeight = window.innerHeight;
            }).resize();
            $('.side_toggle, .side_overlay').unbind('click').click(function() {
                if (!side.hasClass('side_open')) {
                    $('body').addClass('body_none_scroll');
                    side.addClass('side_open');
                    over.fadeIn();
                } else {
                    $('body').removeClass('body_none_scroll');
                    side.removeClass('side_open');
                    setTimeout(function() {
                        over.fadeOut('fast');
                    }, 100);
                }
            });
            side.find(".side_scroll>ul>li>a").click(function(e) {
                var tg = $(this);
                if (tg.next('.sub').length > 0 && windowWidth < 1136) {
                    if (tg.next().is(":visible") === false) {
                        side.find(".sub").slideUp(
                            300);
                    }
                    tg.next().slideToggle(300);
                    e.preventDefault();
                }
            });
            var windowPosition = windowScrollTop;
            $(window).scroll(function() {
                windowScrollTop = $(window).scrollTop();
                if (windowScrollTop == windowPosition) return false;
            }).scroll();
            var chkin = $('.datepicker_in');
            var chkot = $('.datepicker_ot');
            var datepicker_ot = new Object;
            var datepicker_in = new Object;
            var period = $('.set_period_date');
            if (chkin.length !== 0) {
                var opt = {
                    format: 'yyyy-mm-dd',
                    language: 'tm',
                    autoclose: !0,
                    startDate: get_today()
                }
                datepicker_in = chkin.datepicker(opt);
            }
            if (chkot.length !== 0) {
                var opt = {
                    format: 'yyyy-mm-dd',
                    language: 'tm',
                    autoclose: !0,
                };
                opt.startDate = chkin.length !== 0 ? calculation_date(chkin.val(), 1, '+') : $('[name*="v_sttdate"]').val();
                datepicker_ot = chkot.datepicker(opt);
            }
            if (chkin.length !== 0 && chkot.length !== 0) {
                datepicker_in.on('changeDate', function() {
                    var click = new convert_date($(this));
                    var click_date = click.getUnix();
                    var out_date = date_unix(datepicker_ot.val());
                    datepicker_ot.datepicker('setStartDate', false);
                    datepicker_ot.datepicker('setDate', click.getOpdt(+1));
                    datepicker_ot.datepicker('setStartDate', click.getOpdt(+1));
                    if ($('.set_period_date').length !== 0) {
                        $('.set_period_date').val(get_period($('.datepicker_in').val(), $('.datepicker_ot').val()));
                    }
                });
                if ($('.set_period_date').length !== 0) {
                    datepicker_ot.on('changeDate', function() {
                        $('.set_period_date').val(get_period($('.datepicker_in').val(), $('.datepicker_ot').val()));
                    });
                }
            }
            if ($('.set_period_date').length !== 0) {
                $('.set_period_date').bind('change keyup', function(
                    event) {
                    var period = $(this).val();
                    if (period != '' && period != 0 && period <= 100) {
                        var date = calculation_date($('.datepicker_in').val(), parseInt(period), '+');
                        datepicker_ot.datepicker('setDate', date);
                    } else {
                        var date = calculation_date($('.datepicker_in').val(), 1, '+');
                        datepicker_ot.datepicker('setDate', date);
                    }
                });
            }
            $(window).load(function() {
                $('.slider_visibility').css({
                    'visibility': 'visible'
                }).hide().fadeIn();
                $('.main_info').show();
                $('.mmain_info').show();
                $(".parallax>div").css("visibility", "visible");
            });
            $(window).resize(function(e) {
                if (side.hasClass('side_open')) {
                    $('body').removeClass('body_none_scroll');
                    side.removeClass('side_open');
                    setTimeout(function() {
                        over.fadeOut('fast');
                    }, 100);
                }
            }).resize();
        },
        mainPage: function() {
            var option = {
                $AutoPlay: !0,
                $SlideshowOptions: {
                    $Class: $JssorSlideshowRunner$,
                    $Transitions: [{
                        $Duration: 1200,
                        $Opacity: 2
                    }],
                    $TransitionsOrder: 1
                },
                $BulletNavigatorOptions: {
                    $Class: $JssorBulletNavigator$,
                    $ChanceToShow: 2,
                    $AutoCenter: 1,
                    $Steps: 1,
                    $Lanes: 1,
                    $SpacingX: 0,
                    $SpacingY: 8,
                    $Orientation: 1,
                    $Scale: !0
                },
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$,
                    $ChanceToShow: 1,
                    $AutoCenter: 2,
                    $Steps: 1
                }
            }
            var jssor_main = new $JssorSlider$('slider_main', option);
            var jssor_mmain = new $JssorSlider$('slider_mmain', option);
            var jssor_rooms = new $JssorSlider$("slider_rooms", {
                $AutoPlay: 1,
                $FillMode: 1,
                $SpacingY: 30,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                },
                $ThumbnailNavigatorOptions: {
                    $Class: $JssorThumbnailNavigator$,
                    $SpacingX: 5,
                    $SpacingY: 5,
                    $ActionMode: 2,
                    $Align: 110,
                    $Loop: 0
                }
            });
            var jssor_desc1 = new $JssorSlider$('slider_desc1', {
                $AutoPlay: 1,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                }
            });
            var jssor_desc2 = new $JssorSlider$('slider_desc2', {
                $AutoPlay: 1,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                }
            });
            var jssor_gallery = new $JssorSlider$("slider_gallery", {
                $AutoPlay: 1,
                $FillMode: 1,
                $SlideWidth: windowWidth < 599 ? 1000 : 425,
                $SlideSpacing: 20,
                $Align: 0,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                },
                $BulletNavigatorOptions: {
                    $Class: $JssorBulletNavigator$
                }
            });
            var ScaleSlider = function() {
                jssor_main.$ScaleWidth(Math.min(jssor_main.$Elmt.parentNode.clientWidth, 1760));
                jssor_mmain.$ScaleWidth(Math.min(jssor_mmain.$Elmt.parentNode.clientWidth, 720));
                jssor_rooms.$ScaleWidth(Math.min(jssor_rooms.$Elmt.parentNode.clientWidth, 1140));
                jssor_desc1.$ScaleWidth(Math.min(jssor_desc1.$Elmt.parentNode.clientWidth, 880));
                jssor_desc2.$ScaleWidth(Math.min(jssor_desc2.$Elmt.parentNode.clientWidth, 880));
                jssor_gallery.$ScaleWidth(Math.min(jssor_gallery.$Elmt.parentNode.clientWidth, 1760));
            }
            $(window).bind("load", ScaleSlider);
            $(window).bind("resize", ScaleSlider);
            $(window).bind("orientationchange", ScaleSlider);
            $('.pop_slider').on('initialized.owl.carousel changed.owl.carousel', function(e) {
                if (!e.namespace) {
                    return;
                }
                var carousel = e.relatedTarget;
                $('.pop_counter').text(carousel.relative(carousel.current()) + 1 + '/' + carousel.items().length);
            }).owlCarousel({
                loop: !0,
                margin: 0,
                items: 1,
                autoplayTimeout: 3000,
                autoplay: !0,
                autoplayHoverPause: !0,
                navText: ['<i Class="icon-arrow-left"></i>', '<i Class="icon-arrow-right"></i>'],
                nav: !0,
                dots: !1
            });
            $(window).load(function() {
                cookiedata = document.cookie;
                var pop = $('.event_pop');
                var cbx = pop.find('input[type=checkbox]');
                cbx.click(function() {
                    setPopCookie("mainpop", "done", 12);
                    pop.hide();
                });
                pop.find('.closebtn').click(function() {
                    pop.hide();
                });
                if (cookiedata.indexOf("mainpop=done") < 0) {
                    pop.show();
                }

                function setPopCookie(name, value, expiredays) {
                    var todayDate = new Date();
                    todayDate.setHours(todayDate.getHours() + expiredays);
                    document.cookie = name + "=" + escape(
                        value) + "; path=/; expires=" + todayDate.toLocaleString() + ";"
                }
            });
            if ($('[data-vbg]').length > 0) $('[data-vbg]').youtube_background();
        },
        aboutPage: function() {
            var jssor_about = new $JssorSlider$('slider_about', {
                $AutoPlay: 1,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                }
            });
            var jssor_gallery = new $JssorSlider$("slider_gallery", {
                $AutoPlay: 1,
                $FillMode: 1,
                $SlideWidth: windowWidth < 599 ? 1000 : 366,
                $SlideSpacing: 20,
                $Align: 0,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                },
            });
            var ScaleSlider = function() {
                jssor_about.$ScaleWidth(Math.min(jssor_about.$Elmt.parentNode.clientWidth, 1140));
                jssor_gallery.$ScaleWidth(Math.min(jssor_gallery.$Elmt.parentNode.clientWidth, 1140));
            }
            $(window).bind("load", ScaleSlider);
            $(window).bind("resize", ScaleSlider);
            $(window).bind("orientationchange", ScaleSlider);
        },
        locationPage: function() {
            kakao.maps.load(function() {
                var container = document.getElementById('map_box');
                var options = {
                    center: new daum.maps.LatLng(container.dataset.lat, container.dataset.long),
                    level: 4
                };
                var map = new daum.maps.Map(container, options);
                var markerPosition = new daum.maps.LatLng(container.dataset.lat, container.dataset.long);
                var marker = new daum.maps.Marker({
                    position: markerPosition
                });
                marker.setMap(map);
            });
        },
        facilitiesPage: function() {
            var jssor_facilities = new $JssorSlider$('slider_facilities', {
                $AutoPlay: 1,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                }
            });
            var ScaleSlider = function() {
                jssor_facilities.$ScaleWidth(Math.min(jssor_facilities.$Elmt.parentNode.clientWidth, 1140));
            }
            $(window).bind("load", ScaleSlider);
            $(window).bind("resize", ScaleSlider);
            $(window).bind("orientationchange", ScaleSlider);
        },
        boardPage: function() {
            if ($('#slider_gallery').length > 0) {
                var jssor_gallery = new $JssorSlider$('slider_gallery', {
                    $AutoPlay: 1,
                    $ArrowNavigatorOptions: {
                        $Class: $JssorArrowNavigator$
                    }
                });
                var ScaleSlider = function() {
                    jssor_gallery.$ScaleWidth(Math.min(jssor_gallery.$Elmt.parentNode.clientWidth, 1140));
                }
                $(window).bind("load", ScaleSlider);
                $(window).bind("resize", ScaleSlider);
                $(window).bind("orientationchange", ScaleSlider);
            }
            $('.faq_box .qs').click(function() {
                var tg = $(this);
                var an = tg.next('.an');
                if (an.css('display') == 'none') {
                    an.slideDown('fast');
                    tg.find('.state i').removeClass('icon-plus').addClass('icon-minus');
                } else {
                    an.slideUp('fast');
                    tg.find('.state i').removeClass('icon-minus').addClass('icon-plus');
                }
            });
        },
        roomsPage: function() {},
        detailPage: function() {
            var jssor_detail = new $JssorSlider$('slider_detail', {
                $AutoPlay: 1,
                $ArrowNavigatorOptions: {
                    $Class: $JssorArrowNavigator$
                }
            });
            var ScaleSlider = function() {
                jssor_detail.$ScaleWidth(Math.min(jssor_detail.$Elmt.parentNode.clientWidth, 1140));
            }
            $(window).bind("load", ScaleSlider);
            $(window).bind("resize", ScaleSlider);
            $(window).bind("orientationchange", ScaleSlider);
        },
        contactPage: function() {
            var bloking = !0;
            var send_mail = function() {
                if (!bloking) return false;
                return validation({
                    v_Name: [$('#v_Name'), '이름'],
                    v_Email: [$('#v_Email'), '이메일', 'EM'],
                    v_Title: [$('#v_Title'), '제목'],
                    v_Content: [$('#v_Content'), '내용'],
                }, function() {
                    $('.page_loader').show();
                    bloking = !1;
                    $.ajax({
                        type: "POST",
                        url: "/main/ajax_send_mail",
                        dataType: "json",
                        data: $('#myForm').serialize(),
                        success: function(obj) {
                            if (obj.state === 'ok') {
                                alert(obj.msg);
                                window.location.reload();
                            } else {
                                alert(obj.msg);
                                window.location.reload();
                            }
                        },
                        beforeSend: function() {
                            $('.page_loader').show();
                        },
                        complete: function() {
                            $('.page_loader').hide();
                        },
                        error: function(e) {
                            console.log(e.responseText);
                            console.log('response error - 관리자 문의 요망 : mail_submit');
                        }
                    });
                });
            };
            $('#send_email').click(send_mail);
        },
    }
    app.common();
    if (main.length > 0) app.mainPage();
    if (about.length > 0) app.aboutPage();
    if (location.length > 0) app.locationPage();
    if (facilities.length > 0) app.facilitiesPage();
    if (board.length > 0) app.boardPage();
    if (rooms.length > 0) app.roomsPage();
    if (detail.length > 0) app.detailPage();
    if (contact.length > 0) app.contactPage();
});